import { useState, useEffect } from 'react';

const API = 'http://localhost:5000/api';

// ── Colors ──
const catInfo = (bmi) => {
  if (bmi < 18.5) return { label: 'Underweight', bg: '#E6F1FB', color: '#185FA5' };
  if (bmi < 25) return { label: 'Normal weight', bg: '#EAF3DE', color: '#3B6D11' };
  if (bmi < 30) return { label: 'Overweight', bg: '#FAEEDA', color: '#854F0B' };
  return { label: 'Obese', bg: '#FCEBEB', color: '#A32D2D' };
};

// ── Tips Data ──
const tipsConvo = [
  { from: 'them', text: '👋 Hey! How are you doing today?', delay: 0 },
  { from: 'me', text: "I'm trying to stay healthy 💪", delay: 600 },
  { from: 'them', text: '🥗 Eat fruits, veggies & protein daily', delay: 1200 },
  { from: 'them', text: '🚫 Avoid junk food & sugar', delay: 1800 },
  { from: 'me', text: 'What about exercise? 🏃', delay: 2400 },
  { from: 'them', text: '🏋️ 30 mins workout daily', delay: 3000 },
  { from: 'them', text: '💡 Mix cardio + strength training', delay: 3600 },
  { from: 'me', text: 'Sleep tips? 😅', delay: 4200 },
  { from: 'them', text: '😴 7–9 hours sleep needed', delay: 4800 },
];

// ── TIP CHAT (UPDATED 🔥) ──
function TipsPage() {
  const [visible, setVisible] = useState([]);
  const [started, setStarted] = useState(false);
  const [typing, setTyping] = useState(false);
  const [input, setInput] = useState('');

  const startChat = () => {
    setStarted(true);
    setVisible([]);

    tipsConvo.forEach((msg) => {
      setTimeout(() => {
        if (msg.from === 'them') setTyping(true);

        setTimeout(() => {
          setTyping(false);
          setVisible(prev => [...prev, msg]);
        }, 500);

      }, msg.delay);
    });
  };

  // ✅ SEND MESSAGE (NEW)
  const sendMessage = () => {
    if (!input.trim()) return;

    const newMsg = {
      from: 'me',
      text: input
    };

    setVisible(prev => [...prev, newMsg]);
    setInput('');
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>

      {/* HEADER */}
      <div style={{ background: '#f5f5f5', padding: 12, textAlign: 'center' }}>
        <div>🏥 Health Coach</div>
        <div style={{ fontSize: 12, color: 'green' }}>Online</div>
      </div>

      {/* CHAT AREA */}
      <div style={{ flex: 1, padding: 12, overflowY: 'auto' }}>

        {!started && (
          <div style={{ textAlign: 'center', marginTop: 80 }}>
            <button onClick={startChat} style={btnPrimary}>
              Start Chat
            </button>
          </div>
        )}

        {visible.map((msg, i) => (
          <div
            key={i}
            style={{
              display: 'flex',
              justifyContent: msg.from === 'me' ? 'flex-end' : 'flex-start',
              marginBottom: 8
            }}
          >
            <div style={{
              background: msg.from === 'me' ? '#007AFF' : '#E5E5EA',
              color: msg.from === 'me' ? 'white' : 'black',
              padding: '8px 12px',
              borderRadius: 18,
              maxWidth: '75%'
            }}>
              {msg.text}
            </div>
          </div>
        ))}

        {typing && (
          <div style={{ fontSize: 12, color: '#888' }}>Typing...</div>
        )}
      </div>

      {/* INPUT BOX (FIXED 🔥) */}
      <div style={{
        display: 'flex',
        gap: 8,
        padding: 10,
        borderTop: '1px solid #ddd',
        background: '#f5f5f5'
      }}>

        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') sendMessage();
          }}
          placeholder="Type a message..."
          style={{
            flex: 1,
            padding: 10,
            borderRadius: 20,
            border: '1px solid #ccc',
            outline: 'none'
          }}
        />

        <button
          onClick={sendMessage}
          style={{
            background: '#007AFF',
            color: 'white',
            border: 'none',
            borderRadius: '50%',
            width: 40,
            height: 40
          }}
        >
          ➤
        </button>
      </div>
    </div>
  );
}

// ── BUTTON STYLE ──
const btnPrimary = {
  padding: 12,
  background: '#534AB7',
  color: 'white',
  border: 'none',
  borderRadius: 10
};

export default function App() {
  return (
    <div>
      <TipsPage />
    </div>
  );
}
